1	/**
2	 * Integration tests for migrate.ts — feat-db-migrations acceptance and review criteria.
3	 *
4	 * AC-1  Fresh DB applies a migration file and records the version in schema_migrations.
5	 * AC-2  Running on a DB where that version is already recorded skips it, emits no error.
6	 * AC-3  A .sql file numbered lower than the highest applied version panics with a
7	 *       message naming both versions.
8	 * AC-4  A migration with a SQL syntax error rolls back completely; schema_migrations
9	 *       is not updated for that version.
10	 * AC-5  Migrations are applied in numeric order regardless of filesystem readdir order.
11	 *
12	 * RC-2  Version comparison is numeric (version 10 sorts after version 9).
13	 * RC-3  Runner refuses to apply if schema_migrations contains a version higher than
14	 *       any known file (forward-only guard).
15	 * RC-4  No migration file is executed more than once per database.
16	 */
17	
18	import { describe, it, expect, beforeEach, afterEach } from 'vitest';
19	import Database from 'better-sqlite3';
20	import fs from 'node:fs';
21	import path from 'node:path';
22	import os from 'node:os';
23	import { applyMigrations } from '../../src/server/storage/migrate.js';
24	
25	// ---------------------------------------------------------------------------
26	// Helpers
27	// ---------------------------------------------------------------------------
28	
29	function makeTestDb(dbPath: string): Database.Database {
30	  const db = new Database(dbPath);
31	  db.pragma('journal_mode = WAL');
32	  db.pragma('foreign_keys = ON');
33	  db.exec(
34	    'CREATE TABLE IF NOT EXISTS schema_migrations ' +
35	      '(version INTEGER PRIMARY KEY, applied_at TEXT NOT NULL)',
36	  );
37	  return db;
38	}
39	
40	function makeDir(parent: string, name: string): string {
41	  const dir = path.join(parent, name);
42	  fs.mkdirSync(dir, { recursive: true });
43	  return dir;
44	}
45	
46	function writeSql(dir: string, filename: string, sql: string): void {
47	  fs.writeFileSync(path.join(dir, filename), sql, 'utf-8');
48	}
49	
50	function appliedVersions(db: Database.Database): number[] {
51	  return (
52	    db.prepare('SELECT version FROM schema_migrations ORDER BY version ASC').all() as {
53	      version: number;
54	    }[]
55	  ).map((r) => r.version);
56	}
57	
58	let tmpDir: string;
59	
60	beforeEach(() => {
61	  tmpDir = fs.mkdtempSync(path.join(os.tmpdir(), 'yoke-migrate-test-'));
62	});
63	
64	afterEach(() => {
65	  fs.rmSync(tmpDir, { recursive: true, force: true });
66	});
67	
68	// ---------------------------------------------------------------------------
69	// AC-1: Fresh DB applies migration and records version
70	// ---------------------------------------------------------------------------
71	
72	describe('AC-1: fresh DB applies migration and records version', () => {
73	  it('applies 0001 and records version 1 in schema_migrations', () => {
74	    const migrDir = makeDir(tmpDir, 'migrations');
75	    writeSql(migrDir, '0001_initial.sql', 'CREATE TABLE t1 (id INTEGER PRIMARY KEY);');
76	
77	    const db = makeTestDb(path.join(tmpDir, 'test.db'));
78	    applyMigrations(db, migrDir);
79	
80	    const row = db
81	      .prepare('SELECT version FROM schema_migrations WHERE version = 1')
82	      .get() as { version: number } | undefined;
83	    const tableExists = db
84	      .prepare("SELECT name FROM sqlite_master WHERE type='table' AND name='t1'")
85	      .get();
86	    db.close();
87	
88	    expect(row?.version).toBe(1);
89	    expect(tableExists).toBeDefined();
90	  });
91	
92	  it('applies multiple migrations on a fresh DB', () => {
93	    const migrDir = makeDir(tmpDir, 'migrations');
94	    writeSql(migrDir, '0001_t1.sql', 'CREATE TABLE t1 (id INTEGER PRIMARY KEY);');
95	    writeSql(migrDir, '0002_t2.sql', 'CREATE TABLE t2 (id INTEGER PRIMARY KEY);');
96	    writeSql(migrDir, '0003_t3.sql', 'CREATE TABLE t3 (id INTEGER PRIMARY KEY);');
97	
98	    const db = makeTestDb(path.join(tmpDir, 'test.db'));
99	    applyMigrations(db, migrDir);
100	
101	    expect(appliedVersions(db)).toEqual([1, 2, 3]);
102	    db.close();
103	  });
104	});
105	
106	// ---------------------------------------------------------------------------
107	// AC-2: Already-applied versions are skipped
108	// ---------------------------------------------------------------------------
109	
110	describe('AC-2: already-applied versions are skipped without error', () => {
111	  it('calling applyMigrations twice on the same DB is idempotent', () => {
112	    const migrDir = makeDir(tmpDir, 'migrations');
113	    writeSql(migrDir, '0001_t1.sql', 'CREATE TABLE t1 (id INTEGER PRIMARY KEY);');
114	
115	    const db = makeTestDb(path.join(tmpDir, 'test.db'));
116	    applyMigrations(db, migrDir);
117	
118	    expect(() => applyMigrations(db, migrDir)).not.toThrow();
119	    expect(appliedVersions(db)).toHaveLength(1);
120	    db.close();
121	  });
122	
123	  it('only applies newly added migration on second call', () => {
124	    const migrDir = makeDir(tmpDir, 'migrations');
125	    writeSql(migrDir, '0001_t1.sql', 'CREATE TABLE t1 (id INTEGER PRIMARY KEY);');
126	    writeSql(migrDir, '0002_t2.sql', 'CREATE TABLE t2 (id INTEGER PRIMARY KEY);');
127	
128	    const db = makeTestDb(path.join(tmpDir, 'test.db'));
129	    applyMigrations(db, migrDir); // applies 0001 and 0002
130	
131	    writeSql(migrDir, '0003_t3.sql', 'CREATE TABLE t3 (id INTEGER PRIMARY KEY);');
132	    applyMigrations(db, migrDir); // should skip 0001, 0002; apply 0003
133	
134	    expect(appliedVersions(db)).toEqual([1, 2, 3]);
135	    db.close();
136	  });
137	
138	  it('no migration SQL is re-executed on repeated calls', () => {
139	    const migrDir = makeDir(tmpDir, 'migrations');
140	    // If CREATE TABLE were executed twice, it would throw "table already exists"
141	    writeSql(migrDir, '0001_t1.sql', 'CREATE TABLE t1 (id INTEGER PRIMARY KEY);');
142	
143	    const db = makeTestDb(path.join(tmpDir, 'test.db'));
144	    applyMigrations(db, migrDir);
145	
146	    // Second call must not re-run the CREATE TABLE statement
147	    expect(() => applyMigrations(db, migrDir)).not.toThrow();
148	    db.close();
149	  });
150	});
151	
152	// ---------------------------------------------------------------------------
153	// AC-3: Panic when file version < highest applied version
154	// ---------------------------------------------------------------------------
155	
156	describe('AC-3: throws when migration file has version lower than highest applied', () => {
157	  it('throws with a message naming both the file version and the max applied version', () => {
158	    const migrDir = makeDir(tmpDir, 'migrations');
159	    // Apply only version 2 first
160	    writeSql(migrDir, '0002_t2.sql', 'CREATE TABLE t2 (id INTEGER PRIMARY KEY);');
161	
162	    const db = makeTestDb(path.join(tmpDir, 'test.db'));
163	    applyMigrations(db, migrDir); // DB now has version 2 applied
164	
165	    // Retroactively add version 1 — regression
166	    writeSql(migrDir, '0001_t1.sql', 'CREATE TABLE t1 (id INTEGER PRIMARY KEY);');
167	
168	    let error: Error | undefined;
169	    try {
170	      applyMigrations(db, migrDir);
171	    } catch (e) {
172	      error = e as Error;
173	    }
174	    db.close();
175	
176	    expect(error).toBeDefined();
177	    expect(error!.message).toContain('version 1'); // file version
178	    expect(error!.message).toContain('version 2'); // max applied
179	  });
180	
181	  it('error message names the specific retroactive file and the highest applied version', () => {
182	    const migrDir = makeDir(tmpDir, 'migrations');
183	    writeSql(migrDir, '0005_t5.sql', 'CREATE TABLE t5 (id INTEGER PRIMARY KEY);');
184	
185	    const db = makeTestDb(path.join(tmpDir, 'test.db'));
186	    applyMigrations(db, migrDir); // DB now has version 5 applied
187	
188	    // Retroactively add version 3
189	    writeSql(migrDir, '0003_t3.sql', 'CREATE TABLE t3 (id INTEGER PRIMARY KEY);');
190	
191	    let error: Error | undefined;
192	    try {
193	      applyMigrations(db, migrDir);
194	    } catch (e) {
195	      error = e as Error;
196	    }
197	    db.close();
198	
199	    expect(error).toBeDefined();
200	    expect(error!.message).toContain('version 3'); // retroactive file version
201	    expect(error!.message).toContain('version 5'); // max applied version
202	  });
203	
204	  it('does not apply the retroactive file when regression is detected', () => {
205	    const migrDir = makeDir(tmpDir, 'migrations');
206	    writeSql(migrDir, '0003_t3.sql', 'CREATE TABLE t3 (id INTEGER PRIMARY KEY);');
207	
208	    const db = makeTestDb(path.join(tmpDir, 'test.db'));
209	    applyMigrations(db, migrDir); // version 3 applied
210	
211	    writeSql(migrDir, '0002_t2.sql', 'CREATE TABLE t2 (id INTEGER PRIMARY KEY);');
212	
213	    try {
214	      applyMigrations(db, migrDir);
215	    } catch {
216	      // expected
217	    }
218	
219	    // Version 2 must NOT have been inserted into schema_migrations
220	    expect(appliedVersions(db)).toEqual([3]);
221	    db.close();
222	  });
223	});
224	
225	// ---------------------------------------------------------------------------
226	// AC-4: SQL syntax error causes complete rollback
227	// ---------------------------------------------------------------------------
228	
229	describe('AC-4: SQL syntax error causes complete rollback', () => {
230	  it('failed migration is not recorded in schema_migrations', () => {
231	    const migrDir = makeDir(tmpDir, 'migrations');
232	    writeSql(migrDir, '0001_valid.sql', 'CREATE TABLE t1 (id INTEGER PRIMARY KEY);');
233	    writeSql(migrDir, '0002_invalid.sql', 'THIS IS NOT VALID SQL!!!;');
234	
235	    const db = makeTestDb(path.join(tmpDir, 'test.db'));
236	    // Both files discovered in one call: 0001 commits its own transaction,
237	    // then 0002 throws — the call propagates the error.
238	    expect(() => applyMigrations(db, migrDir)).toThrow();
239	
240	    // 0001 committed before 0002 failed; only version 1 is recorded.
241	    expect(appliedVersions(db)).toEqual([1]);
242	    db.close();
243	  });
244	
245	  it('table created in same migration as syntax error does not persist', () => {
246	    const migrDir = makeDir(tmpDir, 'migrations');
247	    // Migration creates a table then hits a syntax error in the same file
248	    writeSql(
249	      migrDir,
250	      '0001_partial.sql',
251	      'CREATE TABLE partial_tbl (id INTEGER PRIMARY KEY);\nINVALID SQL HERE;',
252	    );
253	
254	    const db = makeTestDb(path.join(tmpDir, 'test.db'));
255	    expect(() => applyMigrations(db, migrDir)).toThrow();
256	
257	    // The table must NOT exist — the transaction was rolled back
258	    const tableExists = db
259	      .prepare("SELECT name FROM sqlite_master WHERE type='table' AND name='partial_tbl'")
260	      .get();
261	    db.close();
262	
263	    expect(tableExists).toBeUndefined();
264	  });
