269	      migrDir,
270	      '0001_bad.sql',
271	      'CREATE TABLE bad_tbl (id INTEGER PRIMARY KEY);\nBAD SYNTAX;',
272	    );
273	
274	    const db = makeTestDb(path.join(tmpDir, 'test.db'));
275	    try {
276	      applyMigrations(db, migrDir);
277	    } catch {
278	      // expected
279	    }
280	
281	    expect(appliedVersions(db)).toHaveLength(0);
282	    db.close();
283	  });
284	});
