290	describe('AC-5: migrations applied in numeric order regardless of readdir order', () => {
291	  it('applies 3 migrations in version order even if written to disk in reverse', () => {
292	    const migrDir = makeDir(tmpDir, 'migrations');
293	    // Write in reverse order to exercise sort independence from filesystem order
294	    writeSql(migrDir, '0003_t3.sql', 'CREATE TABLE t3 (id INTEGER PRIMARY KEY);');
295	    writeSql(migrDir, '0001_t1.sql', 'CREATE TABLE t1 (id INTEGER PRIMARY KEY);');
296	    writeSql(migrDir, '0002_t2.sql', 'CREATE TABLE t2 (id INTEGER PRIMARY KEY);');
