305	  it('a migration that depends on a prior table applies after that prior table exists', () => {
306	    const migrDir = makeDir(tmpDir, 'migrations');
307	    // 0002 inserts into t1 which is created by 0001 — ordering is critical
308	    writeSql(migrDir, '0002_insert.sql', "INSERT INTO t1 VALUES (42);");
309	    writeSql(migrDir, '0001_t1.sql', 'CREATE TABLE t1 (id INTEGER PRIMARY KEY);');
310	
311	    const db = makeTestDb(path.join(tmpDir, 'test.db'));
312	    expect(() => applyMigrations(db, migrDir)).not.toThrow();
313	
314	    const row = db.prepare('SELECT id FROM t1').get() as { id: number } | undefined;
315	    db.close();
316	    expect(row?.id).toBe(42);
